287→private final class InMemoryProfileRepository: UserProfileRepository, @unchecked Sendable {
288→    private var profile: UserProfile?
289→    func loadProfile() async throws -> UserProfile? { profile }
290→    func saveProfile(_ profile: UserProfile) async throws { self.profile = profile }
291→}
292→
293→private final class InMemoryEntitlementRepository: EntitlementRepository, @unchecked Sendable {
294→    func currentEntitlement() async throws -> ProEntitlement { .free }
295→    func entitlementStream() -> AsyncStream<ProEntitlement> {
296→        AsyncStream { continuation in continuation.finish() }
297→    }
298→}
299→
300→private final class InMemoryHistoryRepository: WorkoutHistoryRepository {
301→    private var entries: [WorkoutHistoryEntry] = []
302→
303→    func listEntries() async throws -> [WorkoutHistoryEntry] {
304→        entries.sorted { $0.date > $1.date }
305→    }
306→    
307→    func listEntries(limit: Int, offset: Int) async throws -> [WorkoutHistoryEntry] {
308→        let sorted = entries.sorted { $0.date > $1.date }
309→        let start = min(offset, sorted.count)
310→        let end = min(offset + limit, sorted.count)
311→        return Array(sorted[start..<end])
312→    }
313→    
314→    func count() async throws -> Int {
315→        entries.count
316→    }
317→
318→    func saveEntry(_ entry: WorkoutHistoryEntry) async throws {
319→        entries.append(entry)
320→    }
321→
322→    func listAppEntriesWithPlan(limit: Int) async throws -> [WorkoutHistoryEntry] {
323→        let filtered = entries
324→            .filter { $0.source == .app && $0.workoutPlan != nil }
325→            .sorted { $0.date > $1.date }
326→        return Array(filtered.prefix(limit))
327→    }
328→}
