330→    private func exportToHealthKitIfPossible() async {
331→        guard status == .completed else { return }
332→        guard canUseHealthKit, healthKitState == .authorized else {
333→            healthKitExportMessage = "Conecte o Apple Health antes de exportar."
334→            return
335→        }
336→        guard let plan = sessionStore.plan else { return }
337→        guard
338→            let healthKit = resolver.resolve(HealthKitServicing.self),
339→            let historyRepo = resolver.resolve(WorkoutHistoryRepository.self)
340→        else { return }
341→        
342→        do {
343→            isExportingHealthKit = true
344→            defer { isExportingHealthKit = false }
345→            
346→            let receipt = try await healthKit.exportWorkout(plan: plan, completedAt: Date())
347→            
348→            // Vincular UUID ao último item do histórico com este planId (melhor esforço)
349→            let recent = try await historyRepo.listEntries(limit: 20, offset: 0)
350→            if let idx = recent.firstIndex(where: { $0.planId == plan.id }) {
351→                var updated = recent[idx]
352→                updated.healthKitWorkoutUUID = receipt.workoutUUID
353→                try await historyRepo.saveEntry(updated)
354→            }
355→            
356→            healthKitExportMessage = "Exportado para Apple Health."
