362→    private func generateNewWorkout() {
363→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
364→              let blocksRepo = resolver.resolve(WorkoutBlocksRepository.self),
365→              let composer = resolver.resolve(WorkoutPlanComposing.self) else {
366→            errorMessage = "Não foi possível carregar as configurações necessárias."
367→            return
368→        }
369→        
370→        isGeneratingNewPlan = true
371→        
372→        Task {
373→            do {
374→                // Busca o último checkIn usado (pode ser armazenado em UserDefaults ou no sessionStore)
375→                // Por enquanto, vamos usar o checkIn padrão baseado no perfil
376→                let profileUseCase = GetUserProfileUseCase(repository: profileRepo)
377→                guard let profile = try await profileUseCase.execute() else {
378→                    errorMessage = "Perfil não encontrado. Configure seu perfil primeiro."
379→                    isGeneratingNewPlan = false
380→                    return
381→                }
382→                
383→                // Gera um novo checkIn baseado no último foco usado (ou padrão)
384→                // Para simplificar, vamos usar o mesmo foco do plano atual
385→                let currentFocus = sessionStore.plan?.focus ?? .fullBody
386→                let checkIn = DailyCheckIn(
387→                    focus: currentFocus,
388→                    sorenessLevel: .none, // Novo treino sem considerar dor anterior
389→                    sorenessAreas: [],
390→                    energyLevel: 5
391→                )
392→                
393→                let generator = GenerateWorkoutPlanUseCase(
394→                    blocksRepository: blocksRepo,
395→                    composer: composer
396→                )
397→                let newPlan = try await generator.execute(profile: profile, checkIn: checkIn)
398→                
399→                await MainActor.run {
400→                    sessionStore.reset()
401→                    sessionStore.start(with: newPlan)
402→                    isGeneratingNewPlan = false
403→                    
404→                    // Navega para o novo treino
405→                    router.pop(on: .home) // summary
406→                    router.push(.workoutPlan(newPlan.id), on: .home)
407→                }
408→            } catch {
409→                await MainActor.run {
410→                    errorMessage = error.localizedDescription
411→                    isGeneratingNewPlan = false
412→                }
413→            }
414→        }
415→    }
