418→        sessionStore.reset()
419→        router.pop(on: .home) // summary
420→        router.pop(on: .home) // detail
421→        router.pop(on: .home) // workout list
422→
423→        if goToHistory {
424→            router.select(tab: .activity)
425→        }
426→    }
