  8→import Foundation
  9→// Combine removido - usando @Observable
 10→import Swinject
 11→import UIKit
 12→
 13→// 💡 Learn: @Observable oferece melhor performance para state management
 14→@MainActor
 15→@Observable final class WorkoutSessionStore {
 16→    // MARK: - Published State
 17→    
 18→    private(set) var session: WorkoutSession?
 19→    private(set) var currentExerciseIndex: Int = 0
 20→    private(set) var skippedExerciseIDs: Set<String> = []
 21→    private(set) var lastCompletionStatus: WorkoutStatus?
 22→    private(set) var isSavingCompletion = false
 23→    private(set) var progress: WorkoutProgress?
 24→    private(set) var lastWorkoutElapsedSeconds: Int = 0
 25→    
 26→    /// Mapa de substituições: ID do exercício original → Alternativa escolhida
 27→    private(set) var substitutions: [String: AlternativeExercise] = [:]
 28→    
 29→    // 💡 Learn: Estado de erro para indicar falha de DI
 30→    private(set) var dependencyError: String?
 31→
 32→    // MARK: - Private
 33→
 34→    private let startUseCase = StartWorkoutSessionUseCase()
 35→    private let completeUseCase: CompleteWorkoutSessionUseCase?
 36→    private let syncWorkoutUseCase: SyncWorkoutCompletionUseCase?
 37→    private let persistenceKey = WorkoutProgress.persistenceKey
 38→    private let substitutionsKey = "active_workout_substitutions"
 39→
 40→    init(resolver: Resolver) {
 41→        // 💡 Learn: Tratamento gracioso de erro em vez de fatalError
 42→        if let historyRepository = resolver.resolve(WorkoutHistoryRepository.self) {
 43→            // HealthKit sync use case - optional
 44→            let healthKitSyncUseCase = resolver.resolve(SyncWorkoutWithHealthKitUseCase.self)
 45→            // User stats update use case - optional
 46→            let updateStatsUseCase = resolver.resolve(UpdateUserStatsUseCase.self)
 47→
 48→            self.completeUseCase = CompleteWorkoutSessionUseCase(
 49→                historyRepository: historyRepository,
 50→                healthKitSyncUseCase: healthKitSyncUseCase,
 51→                updateStatsUseCase: updateStatsUseCase
 52→            )
 53→        } else {
 54→            self.completeUseCase = nil
 55→            self.dependencyError = "Repositório de histórico não configurado"
 56→        }
 57→
 58→        // Social sync use case - optional (may not be configured)
 59→        self.syncWorkoutUseCase = resolver.resolve(SyncWorkoutCompletionUseCase.self)
 60→
 61→        // Tentar restaurar sessão ativa ao iniciar
 62→        restoreSessionIfNeeded()
 63→        restoreSubstitutions()
 64→    }
 65→    
 66→    // MARK: - Session Lifecycle
 67→
 68→    func start(with plan: WorkoutPlan) {
 69→        session = startUseCase.execute(plan: plan)
 70→        currentExerciseIndex = 0
 71→        skippedExerciseIDs = []
 72→        lastCompletionStatus = nil
 73→        
 74→        // Inicializar tracking de progresso
 75→        progress = WorkoutProgress(from: plan)
 76→        persistProgress()
 77→    }
 78→
 79→    func reset() {
 80→        session = nil
 81→        currentExerciseIndex = 0
 82→        skippedExerciseIDs = []
 83→        lastCompletionStatus = nil
 84→        isSavingCompletion = false
 85→        progress = nil
 86→        lastWorkoutElapsedSeconds = 0
 87→
 88→        clearPersistedProgress()
 89→    }
 90→
 91→    /// Records the elapsed workout time (in seconds) before the session is finalized.
 92→    /// Called by the execution UI right before calling finish(status:).
 93→    func recordElapsedTime(_ seconds: Int) {
 94→        lastWorkoutElapsedSeconds = seconds
 95→    }
 96→
 97→    /// Returns a formatted string for the last workout's elapsed time (MM:SS or H:MM:SS).
 98→    var formattedLastWorkoutTime: String {
 99→        let total = lastWorkoutElapsedSeconds
100→        let hours = total / 3600
101→        let minutes = (total % 3600) / 60
102→        let seconds = total % 60
103→        if hours > 0 {
104→            return String(format: "%d:%02d:%02d", hours, minutes, seconds)
105→        }
106→        return String(format: "%02d:%02d", minutes, seconds)
107→    }
108→    
109→    // MARK: - Computed Properties
110→
111→    var plan: WorkoutPlan? {
112→        session?.plan
113→    }
114→
115→    var exercises: [ExercisePrescription] {
116→        session?.plan.exercises ?? []
117→    }
118→
119→    var exerciseCount: Int {
120→        exercises.count
121→    }
122→
123→    var currentPrescription: ExercisePrescription? {
124→        guard exercises.indices.contains(currentExerciseIndex) else { return nil }
125→        return exercises[currentExerciseIndex]
126→    }
127→    
128→    /// Progresso do exercício atual
129→    var currentExerciseProgress: ExerciseProgress? {
130→        guard let progress, exercises.indices.contains(currentExerciseIndex) else { return nil }
131→        return progress.exercises[currentExerciseIndex]
132→    }
133→    
134→    /// Progresso geral do treino (0.0 - 1.0)
135→    var overallProgress: Double {
136→        progress?.overallProgressPercentage ?? 0
137→    }
138→    
139→    /// Contagem de exercícios completos
140→    var completedExercisesCount: Int {
141→        progress?.completedExercisesCount ?? 0
142→    }
143→    
144→    // MARK: - Navigation
145→
146→    func selectExercise(at index: Int) {
147→        guard exercises.indices.contains(index) else { return }
148→        currentExerciseIndex = index
149→    }
150→
151→    func advanceToNextExercise() -> Bool {
152→        guard exercises.count > 0 else { return true }
153→        if currentExerciseIndex < exercises.count - 1 {
154→            currentExerciseIndex += 1
155→            return false
156→        } else {
157→            return true
158→        }
159→    }
160→
161→    func skipCurrentExercise() -> Bool {
162→        if let exerciseID = currentPrescription?.exercise.id {
163→            skippedExerciseIDs.insert(exerciseID)
164→        }
165→        
166→        // Marcar como pulado no progress
167→        progress?.skipExercise(at: currentExerciseIndex)
168→        persistProgress()
169→        
170→        return advanceToNextExercise()
171→    }
172→    
173→    // MARK: - Set Tracking
174→    
175→    /// Alterna o estado de uma série específica
176→    func toggleSet(exerciseIndex: Int, setIndex: Int) {
177→        progress?.toggleSet(exerciseIndex: exerciseIndex, setIndex: setIndex)
178→        persistProgress()
179→        
180→        // Haptic feedback
181→        triggerSetCompletionHaptic()
182→    }
183→    
184→    /// Alterna o estado de uma série do exercício atual
185→    func toggleCurrentExerciseSet(at setIndex: Int) {
186→        toggleSet(exerciseIndex: currentExerciseIndex, setIndex: setIndex)
187→    }
188→    
189→    /// Update actual reps for a specific set
190→    func updateSetReps(exerciseIndex: Int, setIndex: Int, reps: Int?) {
191→        progress?.updateSetReps(exerciseIndex: exerciseIndex, setIndex: setIndex, reps: reps)
192→        persistProgress()
193→    }
194→
195→    /// Update weight for a specific set
196→    func updateSetWeight(exerciseIndex: Int, setIndex: Int, weight: Double?) {
197→        progress?.updateSetWeight(exerciseIndex: exerciseIndex, setIndex: setIndex, weight: weight)
198→        persistProgress()
199→    }
200→
201→    /// Marca todas as séries do exercício atual como concluídas
202→    func completeAllCurrentSets() {
203→        progress?.completeAllSets(exerciseIndex: currentExerciseIndex)
204→        persistProgress()
205→        triggerSetCompletionHaptic()
206→    }
207→    
208→    /// Verifica se o exercício atual está completo
209→    var isCurrentExerciseComplete: Bool {
210→        guard let currentExerciseProgress else { return false }
211→        return currentExerciseProgress.isFullyCompleted
212→    }
213→    
214→    // MARK: - Exercise Substitution
215→    
216→    /// Aplica uma substituição para o exercício atual
217→    func substituteCurrentExercise(with alternative: AlternativeExercise) {
218→        guard let currentPrescription else { return }
219→        let originalId = currentPrescription.exercise.id
220→        substitutions[originalId] = alternative
221→        persistSubstitutions()
222→        
223→        // Haptic feedback
224→        let generator = UINotificationFeedbackGenerator()
225→        generator.notificationOccurred(.success)
226→    }
227→    
228→    /// Retorna a alternativa para um exercício, se existir
229→    func substitution(for exerciseId: String) -> AlternativeExercise? {
230→        substitutions[exerciseId]
231→    }
232→    
233→    /// Verifica se o exercício atual tem substituição
234→    var currentExerciseHasSubstitution: Bool {
235→        guard let currentPrescription else { return false }
236→        return substitutions[currentPrescription.exercise.id] != nil
237→    }
238→    
239→    /// Retorna o exercício atual (original ou substituído)
240→    var effectiveCurrentExerciseName: String {
241→        guard let currentPrescription else { return "" }
242→        if let sub = substitutions[currentPrescription.exercise.id] {
243→            return sub.name
244→        }
245→        return currentPrescription.exercise.name
246→    }
247→    
248→    /// Remove substituição do exercício atual
249→    func removeCurrentSubstitution() {
250→        guard let currentPrescription else { return }
251→        substitutions.removeValue(forKey: currentPrescription.exercise.id)
252→        persistSubstitutions()
253→    }
254→    
255→    private func persistSubstitutions() {
256→        do {
257→            let data = try JSONEncoder().encode(substitutions)
258→            UserDefaults.standard.set(data, forKey: substitutionsKey)
259→        } catch {
260→            print("Failed to persist substitutions: \(error)")
261→        }
262→    }
263→    
264→    private func restoreSubstitutions() {
265→        guard let data = UserDefaults.standard.data(forKey: substitutionsKey),
266→              let saved = try? JSONDecoder().decode([String: AlternativeExercise].self, from: data) else {
267→            return
268→        }
269→        self.substitutions = saved
270→    }
271→    
272→    private func clearSubstitutions() {
273→        substitutions = [:]
274→        UserDefaults.standard.removeObject(forKey: substitutionsKey)
275→    }
276→    
277→    // MARK: - Exercise Removal
278→
279→    /// Removes an exercise from the current workout plan at the specified phase and item index.
280→    /// - Parameters:
281→    ///   - phaseIndex: The index of the phase containing the exercise
282→    ///   - itemIndex: The index of the item within the phase
283→    /// - Returns: true if exercise was removed, false if operation was blocked
284→    @discardableResult
285→    func removeExercise(fromPhase phaseIndex: Int, at itemIndex: Int) -> Bool {
286→        guard var currentSession = session else { return false }
287→        guard phaseIndex < currentSession.plan.phases.count else { return false }
288→        guard itemIndex < currentSession.plan.phases[phaseIndex].items.count else { return false }
289→
290→        // Ensure at least 1 exercise remains in the entire workout
291→        let totalExercises = currentSession.plan.phases.reduce(0) { total, phase in
292→            total + phase.items.filter { if case .exercise = $0 { return true }; return false }.count
293→        }
294→        guard totalExercises > 1 else { return false }
295→
296→        // Remove the item
297→        currentSession.plan.phases[phaseIndex].items.remove(at: itemIndex)
298→
299→        // Remove empty phases
300→        currentSession.plan.phases.removeAll { $0.items.isEmpty }
301→
302→        // Update session
303→        session = currentSession
304→
305→        // Update progress if needed
306→        if var currentProgress = progress {
307→            currentProgress.removeExercise(at: currentProgress.exercises.count > itemIndex ? itemIndex : currentProgress.exercises.count - 1)
308→            progress = currentProgress
309→            persistProgress()
310→        }
311→
312→        // Adjust current exercise index if needed
313→        if currentExerciseIndex >= exercises.count {
314→            currentExerciseIndex = max(0, exercises.count - 1)
315→        }
316→
317→        // Haptic feedback
318→        let generator = UINotificationFeedbackGenerator()
319→        generator.notificationOccurred(.warning)
320→
321→        return true
322→    }
323→
324→    // MARK: - Finish Session
325→
326→    func finish(status: WorkoutStatus) async throws {
327→        guard let session else { throw DomainError.invalidInput(reason: "Nenhum treino ativo.") }
328→        guard !isSavingCompletion else { return }
329→        // 💡 Learn: Verificar dependência opcional antes de usar
330→        guard let useCase = completeUseCase else {
331→            throw DomainError.repositoryFailure(reason: "Serviço de histórico não configurado")
332→        }
333→        isSavingCompletion = true
334→        defer { isSavingCompletion = false }
335→        try await useCase.execute(session: session, status: status)
336→        lastCompletionStatus = status
337→
338→        // Sync to Firebase leaderboard in background (don't block UI)
339→        if status == .completed, let syncUseCase = syncWorkoutUseCase {
340→            // Compute workout duration from session start
341→            let completedAt = Date()
342→            let durationSeconds = completedAt.timeIntervalSince(session.startedAt)
343→            let durationMinutes = Int(durationSeconds / 60)
344→
345→            let entry = WorkoutHistoryEntry(
346→                planId: session.plan.id,
347→                title: session.plan.title,
348→                focus: session.plan.focus,
349→                status: status,
350→                durationMinutes: durationMinutes
351→            )
352→            Task.detached {
353→                await syncUseCase.execute(entry: entry)
354→            }
355→        }
356→
357→        // Limpar persistência após conclusão
358→        clearPersistedProgress()
359→    }
360→    
361→    // MARK: - Persistence
362→    
363→    private func persistProgress() {
364→        guard let progress else { return }
365→        do {
366→            let data = try JSONEncoder().encode(progress)
367→            UserDefaults.standard.set(data, forKey: persistenceKey)
368→        } catch {
369→            print("Failed to persist workout progress: \(error)")
370→        }
371→    }
372→    
373→    private func clearPersistedProgress() {
374→        UserDefaults.standard.removeObject(forKey: persistenceKey)
375→        clearSubstitutions()
376→    }
377→    
378→    private func restoreSessionIfNeeded() {
379→        guard let data = UserDefaults.standard.data(forKey: persistenceKey),
380→              let savedProgress = try? JSONDecoder().decode(WorkoutProgress.self, from: data) else {
381→            return
382→        }
383→        
384→        // Apenas restaurar se foi salvo recentemente (últimas 24h)
385→        let hoursAgo = Date().timeIntervalSince(savedProgress.lastUpdatedAt) / 3600
386→        guard hoursAgo < 24 else {
387→            clearPersistedProgress()
388→            return
389→        }
390→        
391→        // Restaurar o progresso (a sessão/plan precisa ser restaurada separadamente)
392→        self.progress = savedProgress
393→    }
394→    
395→    /// Restaura sessão completa de um plano (chamado quando o app reabre)
396→    func restoreSession(from plan: WorkoutPlan) {
397→        // Se o progress persistido pertence a este plano, restaurar
398→        if let progress, progress.planId == plan.id {
399→            session = startUseCase.execute(plan: plan)
400→            // Encontrar o primeiro exercício não completo
401→            if let firstIncomplete = self.progress?.exercises.firstIndex(where: { !$0.isFullyCompleted && !$0.isSkipped }) {
402→                currentExerciseIndex = firstIncomplete
403→            }
404→        } else {
405→            // Novo treino
406→            start(with: plan)
407→        }
408→    }
409→    
410→    // MARK: - Haptics
411→    
412→    private func triggerSetCompletionHaptic() {
413→        let generator = UIImpactFeedbackGenerator(style: .medium)
414→        generator.impactOccurred()
415→    }
416→}
