func toggleLike(postId: String, userId: String) async throws -> Bool {
    let docRef = postsCollection.document(postId)

    return try await db.runTransaction { transaction, _ in
        let snapshot = try transaction.getDocument(docRef)
        guard var likedBy = snapshot.data()?["likedBy"] as? [String] else {
            return false
        }

        let isNowLiked: Bool
        if likedBy.contains(userId) {
            likedBy.removeAll { $0 == userId }
            isNowLiked = false
        } else {
            likedBy.append(userId)
            isNowLiked = true
        }

        transaction.updateData([
            "likedBy": likedBy,
            "likeCount": likedBy.count
        ], forDocument: docRef)

        return isNowLiked
    }
}

